// Voice-to-copy — placeholder
// 目的：接收 Whisper 逐字稿（文字），送到 Creator 入庫（SSOT）

const tz = 'Asia/Taipei';
const b = $json || {};
const sourceText = (b.sourceText || b.text || '').toString().trim();

return [{
  json: {
    source: 'voice',
    sourceText,
    intent: (b.intent || 'insight').toString(),
    timezone: tz,
    cta: 'line_free_divination',
    channels: ['ig','threads','fb','linkedin']
  }
}];
